def calculate_landscaping_cost(services):
    total_cost = 0.0
    for service, hours in services:
        rate = 0.0
        if service == "Lawn Mowing":
            rate = 50
        elif service == "Tree Trimming":
            rate = 60
        elif service == "Flower Planting":
            rate = 40
        elif service == "General Cleanup":
            rate = 30
        total_cost += hours * rate
    total_cost *= 0.8
    return total_cost

services = [
    ("Lawn Mowing", 10),
    ("Tree Trimming", 5),
    ("Flower Planting", 8),
    ("General Cleanup", 12)
]

result = calculate_landscaping_cost(services)
print(result)
